mapper.select:
select * from ys_tb.ys_goods


        and (name like concat('%',#{map.searchKeyword},'%')
        or introduce like concat('%',#{map.searchKeyword},'%')
        or brand like concat('%',#{map.searchKeyword},'%'))


        and category_id = #{map.categoryId}


        and brand like concat('%',#{map.brand},'%')


        and price >= #{map.priceMin}


        and price <= #{map.priceMax}


        and inventory >= #{map.inventoryMin}




        order by ${map.sortColumn} ${map.sortOrder}


        order by id desc
